import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { useAuth } from '../../context/AuthContext';
import AnimatedNumber from '../../components/AnimatedNumber';

const SEMESTERS = [1,2,3,4,5,6,7,8];
const STATUS_BADGE = { submitted:'badge-yellow', approved:'badge-green', rejected:'badge-red' };

function DetailModal({ title, icon, onClose, children, count, filters, onFilter }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 760 }}>
        <div className="modal-header">
          <span className="modal-title">{icon} {title}</span>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        {filters && (
          <div style={{ padding:'12px 20px', borderBottom:'1px solid var(--border)', background:'#f8fafc', display:'flex', gap:10, flexWrap:'wrap' }}>
            {filters}
          </div>
        )}
        <div style={{ maxHeight:'60vh', overflowY:'auto' }}>{children}</div>
        <div style={{ padding:'12px 20px', borderTop:'1px solid var(--border)', fontSize:13, color:'var(--text-muted)', background:'#f8fafc' }}>
          Showing: <strong>{count}</strong> record{count !== 1 ? 's' : ''}
        </div>
      </div>
    </div>
  );
}

export default function HodDashboard() {
  const { user }  = useAuth();
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState(null);
  const [allData, setAllData] = useState([]);
  const [filtered,setFiltered]= useState([]);
  const [loadingModal, setLoadingModal] = useState(false);

  // Filter states
  const [fSem,    setFSem]    = useState('');
  const [fSec,    setFSec]    = useState('');
  const [fSearch, setFSearch] = useState('');
  const [fStatus, setFStatus] = useState('');
  const [fMid,    setFMid]    = useState('');
  const [sections,setSections]= useState([]);

  useEffect(() => {
    axios.get('/api/hod/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  // Apply filters whenever filter state or allData changes
  useEffect(() => {
    if (!modal) return;
    let result = [...allData];
    if (fSearch) {
      const q = fSearch.toLowerCase();
      result = result.filter(r =>
        r.name?.toLowerCase().includes(q) ||
        r.rollNumber?.toLowerCase().includes(q) ||
        r.student?.name?.toLowerCase().includes(q) ||
        r.student?.rollNumber?.toLowerCase().includes(q) ||
        r.subject?.name?.toLowerCase().includes(q)
      );
    }
    if (fSem) result = result.filter(r => (r.semester || r.subject?.semester) === Number(fSem));
    if (fSec) result = result.filter(r => (r.section || r.student?.section) === fSec);
    if (fStatus) result = result.filter(r => r.status === fStatus);
    if (fMid) result = result.filter(r => r.midExam === fMid);
    setFiltered(result);
  }, [allData, fSearch, fSem, fSec, fStatus, fMid, modal]);

  const openModal = async (type, title, icon) => {
    setModal({ type, title, icon });
    setAllData([]); setFiltered([]);
    setFSem(''); setFSec(''); setFSearch(''); setFStatus(''); setFMid('');
    setLoadingModal(true);
    try {
      if (type === 'students') {
        const res = await axios.get('/api/hod/students');
        setAllData(res.data.students);
        const secs = [...new Set(res.data.students.map(s => s.section).filter(Boolean))].sort();
        setSections(secs);
      } else if (type === 'faculty') {
        const res = await axios.get('/api/hod/faculty');
        setAllData(res.data.faculty);
        setSections([]);
      } else if (type === 'subjects') {
        const res = await axios.get('/api/hod/subjects');
        setAllData(res.data.subjects);
        setSections([]);
      } else if (type === 'pending' || type === 'approved') {
        const res = await axios.get('/api/hod/marks', { params: { status: type === 'pending' ? 'submitted' : 'approved' } });
        setAllData(res.data.marks);
        const secs = [...new Set(res.data.marks.map(m => m.student?.section).filter(Boolean))].sort();
        setSections(secs);
      }
    } catch { setAllData([]); }
    finally { setLoadingModal(false); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data)   return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats, studentsBySem, subjectsBySem } = data;
  const semData = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const subData = subjectsBySem.map(s => ({ name: `Sem ${s._id}`, subjects: s.count }));

  const statCards = [
    { key:'students', value:stats.totalStudents,  label:'Students',          icon:'👨‍🎓', color:'blue',   title:'All Students'      },
    { key:'faculty',  value:stats.totalFaculty,   label:'Faculty Members',   icon:'👩‍🏫', color:'green',  title:'All Faculty'       },
    { key:'subjects', value:stats.totalSubjects,  label:'Subjects',          icon:'📚', color:'cyan',   title:'All Subjects'      },
    { key:'pending',  value:stats.pendingMarks,   label:'Pending Approvals', icon:'⏳', color:'yellow', title:'Pending Marks'     },
    { key:'approved', value:stats.approvedMarks,  label:'Approved Marks',    icon:'✅', color:'green',  title:'Approved Marks'    },
  ];

  const renderFilters = () => {
    if (!modal) return null;
    const t = modal.type;
    return (
      <>
        <input className="form-input-sm" style={{ width:180 }} placeholder="🔍 Search..." value={fSearch} onChange={e => setFSearch(e.target.value)} />
        {(t === 'students' || t === 'pending' || t === 'approved') && (
          <select className="form-select" style={{ width:150 }} value={fSem} onChange={e => setFSem(e.target.value)}>
            <option value="">All Semesters</option>
            {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
          </select>
        )}
        {sections.length > 0 && (
          <select className="form-select" style={{ width:130 }} value={fSec} onChange={e => setFSec(e.target.value)}>
            <option value="">All Sections</option>
            {sections.map(s => <option key={s} value={s}>Section {s}</option>)}
          </select>
        )}
        {(t === 'pending' || t === 'approved') && (
          <select className="form-select" style={{ width:130 }} value={fMid} onChange={e => setFMid(e.target.value)}>
            <option value="">All Exams</option>
            <option value="Mid-1">Mid-1</option>
            <option value="Mid-2">Mid-2</option>
          </select>
        )}
        {(fSearch || fSem || fSec || fStatus || fMid) && (
          <button className="btn btn-outline btn-sm" onClick={() => { setFSearch(''); setFSem(''); setFSec(''); setFStatus(''); setFMid(''); }}>✕ Clear</button>
        )}
      </>
    );
  };

  const renderContent = () => {
    if (loadingModal) return <div className="empty-state" style={{ padding:48 }}><div className="spinner" style={{ margin:'0 auto' }}></div></div>;
    if (!filtered.length) return <div className="empty-state"><div className="empty-icon">📭</div><div className="empty-text">No records found</div></div>;

    if (modal.type === 'students') return (
      <table>
        <thead><tr><th>#</th><th>Name</th><th>Roll No</th><th>Semester</th><th>Section</th></tr></thead>
        <tbody>{filtered.map((s,i) => (
          <tr key={s._id}><td>{i+1}</td><td className="fw-600">{s.name}</td>
            <td style={{ fontFamily:'monospace',fontSize:12 }}>{s.rollNumber}</td>
            <td><span className="badge badge-blue">Sem {s.semester}</span></td>
            <td>{s.section || '—'}</td></tr>
        ))}</tbody>
      </table>
    );

    if (modal.type === 'faculty') return (
      <table>
        <thead><tr><th>#</th><th>Name</th><th>Roll No</th><th>Department</th></tr></thead>
        <tbody>{filtered.map((f,i) => (
          <tr key={f._id}><td>{i+1}</td><td className="fw-600">{f.name}</td>
            <td style={{ fontFamily:'monospace',fontSize:12 }}>{f.rollNumber}</td>
            <td>{f.department?.name || '—'}</td></tr>
        ))}</tbody>
      </table>
    );

    if (modal.type === 'subjects') return (
      <table>
        <thead><tr><th>#</th><th>Subject</th><th>Code</th><th>Semester</th><th>Credits</th></tr></thead>
        <tbody>{filtered.map((s,i) => (
          <tr key={s._id}><td>{i+1}</td><td className="fw-600">{s.name}</td>
            <td><span className="badge badge-purple">{s.code}</span></td>
            <td>Sem {s.semester}</td><td>{s.credits}</td></tr>
        ))}</tbody>
      </table>
    );

    return (
      <table>
        <thead><tr><th>#</th><th>Student</th><th>Roll No</th><th>Sem</th><th>Sec</th><th>Subject</th><th>Exam</th><th>Marks</th><th>Faculty</th><th>Status</th></tr></thead>
        <tbody>{filtered.map((m,i) => (
          <tr key={m._id}><td>{i+1}</td>
            <td className="fw-600">{m.student?.name}</td>
            <td style={{ fontFamily:'monospace',fontSize:11 }}>{m.student?.rollNumber}</td>
            <td>{m.semester}</td>
            <td>{m.student?.section || '—'}</td>
            <td>{m.subject?.name}</td>
            <td><span className="badge badge-blue">{m.midExam}</span></td>
            <td className="fw-600">{m.totalMarks}/30</td>
            <td className="text-muted">{m.faculty?.name}</td>
            <td><span className={`badge ${STATUS_BADGE[m.status]||'badge-gray'}`}>{m.status}</span></td>
          </tr>
        ))}</tbody>
      </table>
    );
  };

  return (
    <div>
      <div className="info-box" style={{ marginBottom:20 }}>
        🏢 Department: <strong>{user?.department?.name}</strong> ({user?.department?.code})
      </div>

      <div className="stats-grid">
        {statCards.map((card, idx) => (
          <div key={card.key}
            className={`stat-card ${card.color} stat-card-animated`}
            style={{ '--delay':`${idx * 0.08}s`, cursor:'pointer', userSelect:'none' }}
            onClick={() => openModal(card.key, card.title, card.icon)}
            title={`Click to view ${card.title}`}
          >
            <div className="stat-icon">{card.icon}</div>
            <div>
              <div className="stat-value"><AnimatedNumber value={card.value} /></div>
              <div className="stat-label">{card.label}</div>
              <div style={{ fontSize:10, color:'var(--primary)', marginTop:2, fontWeight:600 }}>Click to view →</div>
            </div>
          </div>
        ))}
      </div>

      <div className="charts-grid">
        <div className="card">
          <div className="card-header"><span className="card-title">👨‍🎓 Students per Semester</span></div>
          <div className="card-body">
            {semData.length ? <div className="chart-container"><ResponsiveContainer width="100%" height="100%"><BarChart data={semData} margin={{ top:5,right:10,left:-10,bottom:5 }}><XAxis dataKey="name" tick={{ fontSize:11 }}/><YAxis allowDecimals={false} tick={{ fontSize:11 }}/><Tooltip/><Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]}/></BarChart></ResponsiveContainer></div>
            : <div className="empty-state"><div className="empty-text">No data</div></div>}
          </div>
        </div>
        <div className="card">
          <div className="card-header"><span className="card-title">📚 Subjects per Semester</span></div>
          <div className="card-body">
            {subData.length ? <div className="chart-container"><ResponsiveContainer width="100%" height="100%"><BarChart data={subData} margin={{ top:5,right:10,left:-10,bottom:5 }}><XAxis dataKey="name" tick={{ fontSize:11 }}/><YAxis allowDecimals={false} tick={{ fontSize:11 }}/><Tooltip/><Bar dataKey="subjects" fill="#10b981" radius={[4,4,0,0]}/></BarChart></ResponsiveContainer></div>
            : <div className="empty-state"><div className="empty-text">No data</div></div>}
          </div>
        </div>
      </div>

      {modal && (
        <DetailModal title={modal.title} icon={modal.icon} onClose={() => { setModal(null); setAllData([]); setFiltered([]); }} count={filtered.length} filters={renderFilters()}>
          {renderContent()}
        </DetailModal>
      )}
    </div>
  );
}
